+/** A condition accepted by conditional option helpers. */
+export type OptionCondition = string | OptionDependency;
+
+type OptionFlagSpec = OptionName | readonly OptionName[];
+
+function conditionOptions(
+  condition: OptionCondition,
+  required: boolean | undefined,
+): OptionOptions {
+  const dependsOn: OptionDependency = typeof condition === "string"
+    ? { option: condition, ...(required !== undefined && { required }) }
+    : { ...condition, ...(required !== undefined && { required }) };
+  return { dependsOn };
+}
+
+function conditionalOptionImpl<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionFlagSpec,
+  valueParser: ValueParser<M, T> | undefined,
+  required: boolean | undefined,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const names = (typeof flagSpec === "string" ? [flagSpec] : flagSpec) as readonly OptionName[];
+  const options = conditionOptions(condition, required);
+  return valueParser == null
+    ? option(...names, options) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>
+    : option(...names, valueParser, options) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>;
+}
+
+/** Creates an option that requires its condition to be satisfied when used. */
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionFlagSpec,
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionImpl(condition, flagSpec, valueParser, true);
+}
+
+/** Creates an option that is hidden, but still accepted, until its condition is satisfied. */
+export function optionalWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionFlagSpec,
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionImpl(condition, flagSpec, valueParser, false);
+}
+
+/** Creates an option with a conditional dependency. */
+export function conditionalOption<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionFlagSpec,
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionImpl(condition, flagSpec, valueParser, undefined);
+}
